    apa.ORIG_QTY                  AS RJ_TRUST_BOOK_VAL_AMT,  -- [MATCHED] DRD source verified against ODI (ODI projects .ORIG_QTY)
    apa.ORIG_QTY                  AS RJ_TRUST_RLZD_TAX_GAIN_OR_LOSS_AMT,  -- [MATCHED] DRD source verified against ODI (ODI projects .ORIG_QTY)
    apa.ORIG_QTY                  AS BFR_REPYMT_FACE_VAL_AMT,  -- [MATCHED] DRD source verified against ODI (ODI projects .ORIG_QTY)
    apa.ORIG_QTY                  AS BFR_INCM_PYMT_FACE_VAL_AMT,  -- [MATCHED] DRD source verified against ODI (ODI projects .ORIG_QTY)
    apa.ORIG_QTY                  AS BASE_POS_QTY,  -- [MATCHED] DRD source verified against ODI (ODI projects .ORIG_QTY)
