    apa.SCR_PRC_IN_TXN_CCY        AS NO_SIS_SCR_MVMT_TXN_PRC,  -- [MATCHED] DRD source verified against ODI (ODI projects .SCR_PRC_IN_TXN_CCY)
    apa.ORIG_QTY                  AS REIVS_SHR_QTY,  -- [MATCHED] DRD source verified against ODI (ODI projects .ORIG_QTY)
