FROM CCAL_REPL_OWNER.TXN t
  JOIN CCAL_REPL_OWNER.SHDW_TXN_TP shdw_txn_tp ON shdw_txn_tp.SRC_TXN_TP = t.SRC_TXN_TP
  JOIN REFERENCE_REPL_OWNER.IMPCT_ACTION_LKU impct_action_lku ON impct_action_lku.ACTION_CODE = t.SRC_ACTN_CODE
  JOIN CCAL_REPL_OWNER.CL_VAL cl_val ON cl_val.CL_VAL_ID = t.SRC_BUY_SELL_MULTI_ID
  JOIN CCSI_OWNER.AR_GRP_SUBDIM ar_grp_subdim ON ar_grp_subdim.AR_ID = t.AR_ID
  -- TODO: replace CROSS JOIN with operator-supplied ON clause for SSDS_DAL_OWNER.FA_NUMBER_V
  CROSS JOIN SSDS_DAL_OWNER.FA_NUMBER_V fa_number_v
  -- TODO: replace CROSS JOIN with operator-supplied ON clause for SSDS_DAL_OWNER.ENTERPRISE_ENTITY_DIM_V
  CROSS JOIN SSDS_DAL_OWNER.ENTERPRISE_ENTITY_DIM_V enterprise_entity_dim_v
  JOIN CCAL_REPL_OWNER.ACATS_BROKER acats_broker ON acats_broker.BROKER_ID = t.ORIG_SRC_STM_CODE AND T.SRC_STM_ID IN ( 53, 54 )
  JOIN CCSI_OWNER.AR_DIM ar_dim ON ar_dim.AR_ID = t.AR_ID
  JOIN COMMON_OWNER.SRC_STM_DIM src_stm_dim ON src_stm_dim.SRC_STM_ID = t.SRC_STM_ID
  JOIN CCAL_REPL_OWNER.CL_VAL cl_val_2 ON cl_val_2.CL_VAL_ID = t.TXN_ST_ID
  JOIN COMMON_OWNER.DATE_DIM date_dim ON date_dim.CAL_DT = t.TD
  JOIN CIRD_OWNER.EXG_DIM exg_dim ON exg_dim.EXG_CD = t.EXG_CODE
  -- TODO: replace CROSS JOIN with operator-supplied ON clause for COMMON_OWNER.ACG_TP_DIM
  CROSS JOIN COMMON_OWNER.ACG_TP_DIM acg_tp_dim
  JOIN CCAL_REPL_OWNER.APA apa ON apa.EXEC_ID = t.TXN_ID
  JOIN CCAL_REPL_OWNER.J$TXN j$txn ON j$txn.TXN_ID = t.TXN_ID
  -- TODO: replace CROSS JOIN with operator-supplied ON clause for CCAL_REPL_OWNER.AVY_CL
  CROSS JOIN CCAL_REPL_OWNER.AVY_CL avy_cl
  JOIN CCAL_REPL_OWNER.TXN_AVY_CL txn_avy_cl ON txn_avy_cl.TXN_ID = t.TXN_ID
  -- TODO: replace CROSS JOIN with operator-supplied ON clause for CCAL_REPL_OWNER.CCAL_CIRD_PD_MAP
  CROSS JOIN CCAL_REPL_OWNER.CCAL_CIRD_PD_MAP ccal_cird_pd_map
  -- TODO: replace CROSS JOIN with operator-supplied ON clause for COMMON_OWNER.CASH_POS_TP_DIM
  CROSS JOIN COMMON_OWNER.CASH_POS_TP_DIM cash_pos_tp_dim
  -- TODO: replace CROSS JOIN with operator-supplied ON clause for CIRD_OWNER.IMT_PD_DIM
  CROSS JOIN CIRD_OWNER.IMT_PD_DIM imt_pd_dim
  -- TODO: replace CROSS JOIN with operator-supplied ON clause for CIRD_OWNER.CCY_DIM
  CROSS JOIN CIRD_OWNER.CCY_DIM ccy_dim
  JOIN TRANSACTIONS_OWNER.LGCY_CNCL_CMPLN_RSN_TP_DIM lgcy_cncl_cmpln_rsn_tp_dim ON lgcy_cncl_cmpln_rsn_tp_dim.LGCY_CNCL_CMPLN_RSN_TP_ID = t.LGCY_CNCL_CMPLN_RSN_TP_ID
  JOIN TRANSACTIONS_OWNER.LGCY_CNCL_CMPLN_SRC_TP_DIM lgcy_cncl_cmpln_src_tp_dim ON lgcy_cncl_cmpln_src_tp_dim.LGCY_CNCL_CMPLN_SRC_TP_ID = t.LGCY_CNCL_CMPLN_SRC_TP_ID
  JOIN TRANSACTIONS_OWNER.LGCY_MKT_TP_DIM lgcy_mkt_tp_dim ON lgcy_mkt_tp_dim.LGCY_MKT_TP_ID = t.LGCY_MKT_TP_ID
  JOIN TRANSACTIONS_OWNER.LGCY_TRD_CPCTY_TP_DIM lgcy_trd_cpcty_tp_dim ON lgcy_trd_cpcty_tp_dim.LGCY_TRD_CPCTY_TP_ID = t.LGCY_TRD_CPCTY_TP_ID
  JOIN CCAL_REPL_OWNER.TXN_RLTNP txn_rltnp ON txn_rltnp.SRC_TXN_ID = t.TXN_ID
